18→
19→#[tokio::main]
20→async fn main() {
21→    tracing_subscriber::registry()
22→        .with(EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info")))
23→        .with(tracing_subscriber::fmt::layer())
24→        .init();
25→
26→    tracing::info!("Starting FleetReserve Operations Suite backend");
27→
28→    let db_url = std::env::var("DATABASE_URL").unwrap_or_else(|_| "fleetreserve.db".to_string());
29→    let conn = rusqlite::Connection::open(&db_url).expect("Failed to open database");
30→    conn.execute_batch("PRAGMA journal_mode=WAL; PRAGMA foreign_keys=ON;")
31→        .expect("Failed to set pragmas");
32→
33→    run_migrations(&conn);
34→
35→    let encryption_key = std::env::var("ENCRYPTION_KEY")
36→        .unwrap_or_else(|_| "default-change-me-32-byte-key!!".to_string());
37→    let hmac_secret = std::env::var("HMAC_SECRET")
38→        .unwrap_or_else(|_| "default-hmac-secret-change-me!!!".to_string());
39→    let upload_dir = std::env::var("UPLOAD_DIR").unwrap_or_else(|_| "./uploads".to_string());
40→
41→    std::fs::create_dir_all(&upload_dir).expect("Failed to create upload directory");
42→
43→    let state = AppState {
44→        db: Arc::new(Mutex::new(conn)),
45→        encryption_key,
46→        hmac_secret,
47→        upload_dir,
48→    };
49→
50→    let app = routes::build_router(state);
51→
52→    let addr = "0.0.0.0:3001";
53→    tracing::info!("Listening on {}", addr);
54→    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
55→    axum::serve(listener, app).await.unwrap();
56→}
57→
58→fn run_migrations(conn: &rusqlite::Connection) {
59→    let schema = include_str!("../migrations/001_initial_schema.sql");
60→    conn.execute_batch(schema).expect("Failed to run schema migration");
61→
62→    let seed = include_str!("../migrations/002_seed_data.sql");
63→    conn.execute_batch(seed).expect("Failed to run seed migration");
64→
65→    tracing::info!("Database migrations complete");
66→}
