66→    }
67→
68→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
69→
70→    let _ = crate::audit::chain::append_audit_log(
71→        &db, &claims.user_id, &claims.username, "RESTORE", "backup", "",
72→        &serde_json::json!({"source_path": req.path}),
73→    );
74→
75→    Ok(Json(serde_json::json!({"message": "Restore initiated"})))
