 10→pub async fn login(
 11→    State(state): State<AppState>,
 12→    Json(req): Json<LoginRequest>,
 13→) -> Result<Json<LoginResponse>, AppError> {
 14→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
 15→
 16→    let user = crate::repositories::users::find_by_username(&db, &req.username)
 17→        .map_err(|e| AppError::Internal(e.to_string()))?
 18→        .ok_or_else(|| AppError::Auth("Invalid credentials".to_string()))?;
 19→
 20→    if !user.active {
 21→        return Err(AppError::Auth("Account is disabled".to_string()));
 22→    }
 23→
 24→    if !password::verify_password(&req.password, &user.password_hash) {
 25→        return Err(AppError::Auth("Invalid credentials".to_string()));
 26→    }
 27→
 28→    let token = session::create_token(
 29→        &user.id, &user.username, user.role.as_str(),
 30→        user.store_id.as_deref(), &state.hmac_secret,
 31→    );
 32→    let csrf_token = csrf::generate_csrf_token();
 33→
 34→    let _ = crate::audit::chain::append_audit_log(
 35→        &db, &user.id, &user.username, "LOGIN", "user", &user.id,
 36→        &serde_json::json!({"method": "password"}),
 37→    );
 38→
 39→    Ok(Json(LoginResponse {
 40→        token,
 41→        csrf_token,
 42→        user: MaskedUser {
 43→            id: user.id,
 44→            username: masking::mask_username(&user.username),
 45→            display_name: user.display_name,
 46→            role: user.role.as_str().to_string(),
 47→            store_id: user.store_id,
 48→        },
 49→    }))
 50→}
