 85→pub async fn reset_password(
 86→    State(state): State<AppState>,
 87→    Json(req): Json<ResetPasswordRequest>,
 88→) -> Result<Json<serde_json::Value>, AppError> {
 89→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
 90→
 91→    let user = crate::repositories::users::find_by_username(&db, &req.username)
 92→        .map_err(|e| AppError::Internal(e.to_string()))?
 93→        .ok_or_else(|| AppError::Validation("Invalid username or recovery code".to_string()))?;
 94→
 95→    let code_hash = hash_recovery_code(&req.recovery_code);
 96→    let rc = crate::repositories::recovery_codes::find_valid(&db, &user.id, &code_hash)
 97→        .map_err(|e| AppError::Internal(e.to_string()))?
 98→        .ok_or_else(|| AppError::Validation("Invalid or expired recovery code".to_string()))?;
 99→
100→    let new_hash = password::hash_password(&req.new_password)
101→        .map_err(|e| AppError::Internal(e))?;
102→    crate::repositories::users::update_password(&db, &user.id, &new_hash)
103→        .map_err(|e| AppError::Internal(e.to_string()))?;
104→    crate::repositories::recovery_codes::mark_used(&db, &rc.id)
105→        .map_err(|e| AppError::Internal(e.to_string()))?;
106→
107→    let _ = crate::audit::chain::append_audit_log(
108→        &db, &user.id, &user.username, "PASSWORD_RESET", "user", &user.id,
109→        &serde_json::json!({"method": "recovery_code"}),
110→    );
111→
112→    Ok(Json(serde_json::json!({"message": "Password reset successful"})))
113→}
