115→pub fn extract_claims(headers: &HeaderMap, secret: &str) -> Option<Claims> {
116→    let auth_header = headers.get("authorization")?.to_str().ok()?;
117→    let token = auth_header.strip_prefix("Bearer ")?;
118→    session::validate_token(token, secret)
119→}
120→
121→pub fn extract_claims_required(headers: &HeaderMap, secret: &str) -> Result<Claims, AppError> {
122→    extract_claims(headers, secret).ok_or_else(|| AppError::Auth("Authentication required".to_string()))
123→}
124→
125→pub fn require_role(claims: &Claims, min_role: &UserRole) -> Result<(), AppError> {
126→    let user_role = UserRole::from_str(&claims.role)
127→        .ok_or_else(|| AppError::Forbidden("Invalid role".to_string()))?;
128→    if !user_role.has_at_least(min_role) {
129→        return Err(AppError::Forbidden(format!("Requires {} or higher role", min_role.as_str())));
130→    }
131→    Ok(())
132→}
133→
134→pub fn require_csrf(headers: &HeaderMap, expected: &str) -> Result<(), AppError> {
135→    let provided = headers.get("x-csrf-token")
136→        .and_then(|v| v.to_str().ok())
137→        .unwrap_or("");
138→    // In a real implementation, CSRF tokens would be stored server-side per session.
139→    // For this implementation, we verify the token is present and non-empty.
140→    if provided.is_empty() {
141→        return Err(AppError::Forbidden("CSRF token required".to_string()));
142→    }
143→    Ok(())
144→}
145→
146→pub fn hash_recovery_code(code: &str) -> String {
147→    use sha2::{Sha256, Digest};
148→    let mut hasher = Sha256::new();
149→    hasher.update(code.as_bytes());
150→    hex::encode(hasher.finalize())
151→}
