 9→pub async fn upload_file(
10→    State(state): State<AppState>,
11→    headers: HeaderMap,
12→    mut multipart: Multipart,
13→) -> Result<(axum::http::StatusCode, Json<Upload>), AppError> {
14→    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
15→    require_role(&claims, &UserRole::MerchantStaff)?;
16→
17→    let mut file_data: Option<Vec<u8>> = None;
18→    let mut filename = String::new();
19→    let mut vehicle_id: Option<String> = None;
20→    let mut store_id: Option<String> = claims.store_id.clone();
21→
22→    while let Some(field) = multipart.next_field().await.map_err(|e| AppError::Upload(e.to_string()))? {
23→        let name = field.name().unwrap_or("").to_string();
24→        match name.as_str() {
25→            "file" => {
26→                filename = field.file_name().unwrap_or("upload").to_string();
27→                file_data = Some(field.bytes().await.map_err(|e| AppError::Upload(e.to_string()))?.to_vec());
28→            }
29→            "vehicle_id" => {
30→                vehicle_id = Some(field.text().await.map_err(|e| AppError::Upload(e.to_string()))?);
31→            }
32→            "store_id" => {
33→                store_id = Some(field.text().await.map_err(|e| AppError::Upload(e.to_string()))?);
34→            }
35→            _ => {}
36→        }
37→    }
38→
39→    let data = file_data.ok_or_else(|| AppError::Upload("No file provided".to_string()))?;
40→
41→    let validated = crate::services::uploads::validate_upload(&data, &filename)
42→        .map_err(|e| AppError::Upload(e))?;
43→
44→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
45→
46→    if crate::services::uploads::check_duplicate(&db, &validated.fingerprint)
47→        .map_err(|e| AppError::Internal(e.to_string()))? {
48→        return Err(AppError::Conflict("Duplicate file: a file with the same content already exists".to_string()));
49→    }
50→
51→    let upload_id = uuid::Uuid::new_v4().to_string();
52→    let stored_filename = format!("{}.{}", upload_id, if validated.content_type == "image/jpeg" { "jpg" } else { "png" });
53→    let file_path = format!("{}/{}", state.upload_dir, stored_filename);
54→    std::fs::write(&file_path, &validated.data).map_err(|e| AppError::Internal(e.to_string()))?;
55→
56→    let upload = Upload {
57→        id: upload_id.clone(), filename: filename.clone(), content_type: validated.content_type,
58→        size_bytes: validated.data.len() as i64, sha256_fingerprint: validated.fingerprint,
59→        vehicle_id: vehicle_id.clone(), store_id: store_id.clone(), uploader_id: claims.user_id.clone(),
60→    };
61→
62→    crate::repositories::uploads::create(&db, &upload).map_err(|e| AppError::Internal(e.to_string()))?;
63→
64→    let _ = crate::audit::chain::append_audit_log(
65→        &db, &claims.user_id, &claims.username, "CREATE", "upload", &upload_id,
66→        &serde_json::json!({"filename": filename, "vehicle_id": vehicle_id}),
67→    );
68→
69→    Ok((axum::http::StatusCode::CREATED, Json(upload)))
70→}
