 9→pub async fn create_reservation(
10→    State(state): State<AppState>,
11→    headers: HeaderMap,
12→    Json(req): Json<CreateReservationRequest>,
13→) -> Result<(axum::http::StatusCode, Json<serde_json::Value>), AppError> {
14→    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
15→    require_csrf(&headers, "")?;
16→
17→    if req.asset_type != "vehicle" && req.asset_type != "bay" {
18→        return Err(AppError::Validation("asset_type must be 'vehicle' or 'bay'".to_string()));
19→    }
20→
21→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
22→
23→    match crate::services::reservation_engine::create_reservation(&db, &claims.user_id, &claims.username, &req) {
24→        Ok(result) => {
25→            Ok((axum::http::StatusCode::CREATED, Json(serde_json::json!({
26→                "reservation": result.reservation,
27→                "ticket": result.ticket,
28→            }))))
29→        }
30→        Err(conflict) => {
31→            Ok((axum::http::StatusCode::CONFLICT, Json(serde_json::to_value(conflict).unwrap())))
32→        }
33→    }
34→}
