36→pub async fn list_reservations(
37→    State(state): State<AppState>,
38→    headers: HeaderMap,
39→    Query(params): Query<std::collections::HashMap<String, String>>,
40→) -> Result<Json<serde_json::Value>, AppError> {
41→    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
42→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
43→
44→    let reservations = match UserRole::from_str(&claims.role) {
45→        Some(UserRole::Customer) => {
46→            crate::repositories::reservations::find_by_user(&db, &claims.user_id)
47→        }
48→        Some(UserRole::PlatformOps) | Some(UserRole::Administrator) => {
49→            if let Some(store_id) = params.get("store_id") {
50→                crate::repositories::reservations::find_by_store(&db, store_id)
51→            } else {
52→                crate::repositories::reservations::find_all(&db)
53→            }
54→        }
55→        _ => {
56→            let store_id = claims.store_id.as_deref()
57→                .ok_or_else(|| AppError::Forbidden("No store assigned".to_string()))?;
58→            crate::repositories::reservations::find_by_store(&db, store_id)
59→        }
60→    }.map_err(|e| AppError::Internal(e.to_string()))?;
61→
62→    Ok(Json(serde_json::json!({"reservations": reservations})))
63→}
