 9→pub async fn get_ticket(
10→    State(state): State<AppState>,
11→    headers: HeaderMap,
12→    Path(id): Path<String>,
13→) -> Result<Json<Ticket>, AppError> {
14→    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
15→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
16→
17→    let ticket = crate::repositories::tickets::find_by_id(&db, &id)
18→        .map_err(|e| AppError::Internal(e.to_string()))?
19→        .ok_or_else(|| AppError::NotFound("Ticket not found".to_string()))?;
20→
21→    // Customer can only see own tickets
22→    if let Some(UserRole::Customer) = UserRole::from_str(&claims.role) {
23→        let reservation: Result<String, _> = db.query_row(
24→            "SELECT user_id FROM reservations WHERE id = ?1", [&ticket.reservation_id], |row| row.get(0),
25→        );
26→        if let Ok(owner_id) = reservation {
27→            if owner_id != claims.user_id {
28→                return Err(AppError::Forbidden("Access denied".to_string()));
29→            }
30→        }
31→    }
32→
33→    Ok(Json(ticket))
34→}
