  1→use crate::models::Claims;
  2→use chrono::Utc;
  3→use hmac::{Hmac, Mac};
  4→use sha2::Sha256;
  5→
  6→type HmacSha256 = Hmac<Sha256>;
  7→
  8→const SESSION_DURATION_HOURS: i64 = 12;
  9→
 10→pub fn create_token(
 11→    user_id: &str,
 12→    username: &str,
 13→    role: &str,
 14→    store_id: Option<&str>,
 15→    secret: &str,
 16→) -> String {
 17→    let now = Utc::now().timestamp();
 18→    let claims = Claims {
 19→        user_id: user_id.to_string(),
 20→        username: username.to_string(),
 21→        role: role.to_string(),
 22→        store_id: store_id.map(String::from),
 23→        iat: now,
 24→        exp: now + (SESSION_DURATION_HOURS * 3600),
 25→    };
 26→
 27→    let payload = serde_json::to_string(&claims).unwrap();
 28→    let payload_b64 = base64::Engine::encode(&base64::engine::general_purpose::URL_SAFE_NO_PAD, &payload);
 29→
 30→    let mut mac = HmacSha256::new_from_slice(secret.as_bytes()).unwrap();
 31→    mac.update(payload_b64.as_bytes());
 32→    let signature = hex::encode(mac.finalize().into_bytes());
 33→
 34→    format!("{}.{}", payload_b64, signature)
 35→}
 36→
 37→pub fn validate_token(token: &str, secret: &str) -> Option<Claims> {
 38→    let parts: Vec<&str> = token.splitn(2, '.').collect();
 39→    if parts.len() != 2 {
 40→        return None;
 41→    }
 42→
 43→    let payload_b64 = parts[0];
 44→    let signature = parts[1];
 45→
 46→    let mut mac = HmacSha256::new_from_slice(secret.as_bytes()).ok()?;
 47→    mac.update(payload_b64.as_bytes());
 48→    let expected = hex::encode(mac.finalize().into_bytes());
 49→
 50→    if signature != expected {
 51→        return None;
 52→    }
 53→
 54→    let payload_bytes = base64::Engine::decode(
 55→        &base64::engine::general_purpose::URL_SAFE_NO_PAD,
 56→        payload_b64,
 57→    ).ok()?;
 58→    let claims: Claims = serde_json::from_slice(&payload_bytes).ok()?;
 59→
 60→    let now = Utc::now().timestamp();
 61→    if claims.exp < now {
 62→        return None;
 63→    }
 64→
 65→    Some(claims)
 66→}
