  1→use crate::models::Ticket;
  2→use chrono::Utc;
  3→use rand::Rng;
  4→use rusqlite::Connection;
  5→
  6→pub fn generate_ticket(
  7→    conn: &Connection,
  8→    reservation_id: &str,
  9→    valid_from: &str,
 10→    valid_until: &str,
 11→) -> Result<Ticket, String> {
 12→    let ticket_id = uuid::Uuid::new_v4().to_string();
 13→    let ticket_number = generate_ticket_number();
 14→
 15→    let qr_data = serde_json::json!({
 16→        "ticket_number": ticket_number,
 17→        "valid_from": valid_from,
 18→        "valid_until": valid_until,
 19→        "reservation_id": reservation_id,
 20→    })
 21→    .to_string();
 22→
 23→    conn.execute(
 24→        "INSERT INTO tickets (id, ticket_number, reservation_id, qr_data, valid_from, valid_until) VALUES (?1, ?2, ?3, ?4, ?5, ?6)",
 25→        rusqlite::params![ticket_id, ticket_number, reservation_id, qr_data, valid_from, valid_until],
 26→    ).map_err(|e| e.to_string())?;
 27→
 28→    Ok(Ticket {
 29→        id: ticket_id,
 30→        ticket_number,
 31→        reservation_id: reservation_id.to_string(),
 32→        qr_data,
 33→        valid_from: valid_from.to_string(),
 34→        valid_until: valid_until.to_string(),
 35→        redeemed: false,
 36→        redeemed_at: None,
 37→        redeemed_by: None,
 38→        undo_eligible_until: None,
 39→        undone: false,
 40→        undone_at: None,
 41→        undone_by: None,
 42→        undo_reason: None,
 43→    })
 44→}
 45→
 46→fn generate_ticket_number() -> String {
 47→    let mut rng = rand::thread_rng();
 48→    let chars: Vec<char> = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789".chars().collect();
 49→    let suffix: String = (0..8).map(|_| chars[rng.gen_range(0..chars.len())]).collect();
 50→    format!("FR-{}", suffix)
 51→}
 52→
 53→pub fn redeem_ticket(
 54→    conn: &Connection,
 55→    ticket_id: &str,
 56→    redeemed_by: &str,
 57→    redeemed_by_username: &str,
 58→) -> Result<String, String> {
 59→    let (redeemed, undone): (bool, bool) = conn
 60→        .query_row(
 61→            "SELECT redeemed, undone FROM tickets WHERE id = ?1",
 62→            [ticket_id],
 63→            |row| Ok((row.get::<_, i64>(0)? != 0, row.get::<_, i64>(1)? != 0)),
 64→        )
 65→        .map_err(|_| "Ticket not found".to_string())?;
 66→
 67→    if redeemed && !undone {
 68→        return Err("Ticket has already been redeemed".to_string());
 69→    }
 70→
 71→    let now = Utc::now();
 72→    let now_str = now.format("%Y-%m-%dT%H:%M:%SZ").to_string();
 73→    let undo_until = (now + chrono::Duration::minutes(2))
 74→        .format("%Y-%m-%dT%H:%M:%SZ")
 75→        .to_string();
 76→
 77→    conn.execute(
 78→        "UPDATE tickets SET redeemed = 1, redeemed_at = ?1, redeemed_by = ?2, undo_eligible_until = ?3, undone = 0, undone_at = NULL, undone_by = NULL, undo_reason = NULL WHERE id = ?4",
 79→        rusqlite::params![now_str, redeemed_by, undo_until, ticket_id],
 80→    ).map_err(|e| e.to_string())?;
 81→
 82→    // Record redemption
 83→    let redemption_id = uuid::Uuid::new_v4().to_string();
 84→    conn.execute(
 85→        "INSERT INTO ticket_redemptions (id, ticket_id, redeemed_by, redeemed_at) VALUES (?1, ?2, ?3, ?4)",
 86→        rusqlite::params![redemption_id, ticket_id, redeemed_by, now_str],
 87→    ).map_err(|e| e.to_string())?;
 88→
 89→    // Audit log
 90→    let _ = crate::audit::chain::append_audit_log(
 91→        conn, redeemed_by, redeemed_by_username, "REDEEM", "ticket", ticket_id,
 92→        &serde_json::json!({"redeemed_at": now_str}),
 93→    );
 94→
 95→    Ok(now_str)
 96→}
 97→
 98→pub fn undo_redemption(
 99→    conn: &Connection,
100→    ticket_id: &str,
101→    undone_by: &str,
102→    undone_by_username: &str,
103→    reason: &str,
104→) -> Result<(), String> {
105→    if reason.trim().is_empty() {
106→        return Err("Undo reason is required and must not be empty".to_string());
107→    }
108→
109→    let (redeemed, undone, undo_eligible_until): (bool, bool, Option<String>) = conn
110→        .query_row(
111→            "SELECT redeemed, undone, undo_eligible_until FROM tickets WHERE id = ?1",
112→            [ticket_id],
113→            |row| Ok((
114→                row.get::<_, i64>(0)? != 0,
115→                row.get::<_, i64>(1)? != 0,
116→                row.get(2)?,
117→            )),
118→        )
119→        .map_err(|_| "Ticket not found".to_string())?;
120→
121→    if !redeemed {
122→        return Err("Ticket has not been redeemed".to_string());
123→    }
124→    if undone {
125→        return Err("Redemption has already been undone".to_string());
126→    }
127→
128→    // Check 2-minute window
129→    let now = Utc::now();
130→    if let Some(until_str) = undo_eligible_until {
131→        if let Ok(until) = chrono::DateTime::parse_from_rfc3339(&until_str) {
132→            if now > until {
133→                return Err("Undo window has expired (2-minute limit)".to_string());
134→            }
135→        } else if let Ok(until) = chrono::NaiveDateTime::parse_from_str(&until_str, "%Y-%m-%dT%H:%M:%SZ") {
136→            let until_utc = until.and_utc();
137→            if now > until_utc {
138→                return Err("Undo window has expired (2-minute limit)".to_string());
139→            }
140→        }
141→    } else {
142→        return Err("Undo window information not available".to_string());
143→    }
144→
145→    let now_str = now.format("%Y-%m-%dT%H:%M:%SZ").to_string();
146→
147→    conn.execute(
148→        "UPDATE tickets SET undone = 1, undone_at = ?1, undone_by = ?2, undo_reason = ?3 WHERE id = ?4",
149→        rusqlite::params![now_str, undone_by, reason, ticket_id],
150→    ).map_err(|e| e.to_string())?;
151→
152→    // Update the most recent redemption record
153→    conn.execute(
154→        "UPDATE ticket_redemptions SET undone = 1, undone_at = ?1, undone_by = ?2, undo_reason = ?3 WHERE ticket_id = ?4 AND undone = 0 ORDER BY redeemed_at DESC LIMIT 1",
155→        rusqlite::params![now_str, undone_by, reason, ticket_id],
156→    ).map_err(|e| e.to_string())?;
157→
158→    // Audit log
159→    let _ = crate::audit::chain::append_audit_log(
160→        conn, undone_by, undone_by_username, "UNDO", "ticket", ticket_id,
161→        &serde_json::json!({"reason": reason, "undone_at": now_str}),
162→    );
163→
164→    Ok(())
165→}
