  1→use crate::audit::chain::append_audit_log;
  2→use crate::models::*;
  3→use chrono::NaiveDateTime;
  4→use rusqlite::Connection;
  5→
  6→const MAX_RETRIES: u32 = 3;
  7→
  8→pub struct ReservationResult {
  9→    pub reservation: Reservation,
 10→    pub ticket: Ticket,
 11→}
 12→
 13→pub fn create_reservation(
 14→    conn: &Connection,
 15→    user_id: &str,
 16→    username: &str,
 17→    req: &CreateReservationRequest,
 18→) -> Result<ReservationResult, ConflictResponse> {
 19→    let start = NaiveDateTime::parse_from_str(&req.start_time, "%Y-%m-%dT%H:%M:%S")
 20→        .map_err(|_| make_validation_conflict("Invalid start_time format"))?;
 21→    let end = NaiveDateTime::parse_from_str(&req.end_time, "%Y-%m-%dT%H:%M:%S")
 22→        .map_err(|_| make_validation_conflict("Invalid end_time format"))?;
 23→
 24→    if end <= start {
 25→        return Err(make_validation_conflict("end_time must be after start_time"));
 26→    }
 27→
 28→    // Validate within business hours
 29→    let store_start: String = conn
 30→        .query_row(
 31→            "SELECT business_hours_start FROM stores WHERE id = ?1",
 32→            [&req.store_id],
 33→            |row| row.get(0),
 34→        )
 35→        .unwrap_or_else(|_| "07:00".to_string());
 36→    let store_end: String = conn
 37→        .query_row(
 38→            "SELECT business_hours_end FROM stores WHERE id = ?1",
 39→            [&req.store_id],
 40→            |row| row.get(0),
 41→        )
 42→        .unwrap_or_else(|_| "19:00".to_string());
 43→
 44→    let start_time_str = start.format("%H:%M").to_string();
 45→    let end_time_str = end.format("%H:%M").to_string();
 46→    if start_time_str < store_start || end_time_str > store_end {
 47→        return Err(make_validation_conflict("Reservation must be within business hours"));
 48→    }
 49→
 50→    for attempt in 0..MAX_RETRIES {
 51→        match try_create_reservation(conn, user_id, username, req, attempt) {
 52→            Ok(result) => return Ok(result),
 53→            Err(ConflictType::VersionConflict) if attempt < MAX_RETRIES - 1 => {
 54→                tracing::warn!("Reservation attempt {} failed with version conflict, retrying", attempt + 1);
 55→                continue;
 56→            }
 57→            Err(ConflictType::VersionConflict) => {
 58→                tracing::error!("Max retries exceeded for reservation");
 59→                return Err(compute_conflict_response(conn, req));
 60→            }
 61→            Err(ConflictType::BusinessConflict(resp)) => return Err(resp),
 62→        }
 63→    }
 64→
 65→    Err(compute_conflict_response(conn, req))
 66→}
 67→
 68→enum ConflictType {
 69→    VersionConflict,
 70→    BusinessConflict(ConflictResponse),
 71→}
 72→
 73→fn try_create_reservation(
 74→    conn: &Connection,
 75→    user_id: &str,
 76→    username: &str,
 77→    req: &CreateReservationRequest,
 78→    _attempt: u32,
 79→) -> Result<ReservationResult, ConflictType> {
 80→    conn.execute("BEGIN IMMEDIATE", []).map_err(|_| ConflictType::VersionConflict)?;
 81→
 82→    let mut reasons: Vec<ConflictReason> = Vec::new();
 83→
 84→    if req.asset_type == "vehicle" {
 85→        // Check vehicle status and version
 86→        let vehicle_row: Result<(String, String, Option<String>, i64), _> = conn.query_row(
 87→            "SELECT status, store_id, insurance_expiry, version FROM vehicles WHERE id = ?1",
 88→            [&req.asset_id],
 89→            |row| Ok((row.get(0)?, row.get(1)?, row.get(2)?, row.get(3)?)),
 90→        );
 91→
 92→        match vehicle_row {
 93→            Ok((status, _store_id, insurance_expiry, version)) => {
 94→                if status == "in-repair" {
 95→                    reasons.push(ConflictReason::InRepairHold);
 96→                }
 97→                if status == "decommissioned" {
 98→                    let _ = conn.execute("ROLLBACK", []);
 99→                    return Err(ConflictType::BusinessConflict(make_validation_conflict(
100→                        "Vehicle is decommissioned and cannot be reserved",
101→                    )));
102→                }
103→
104→                if let Some(expiry) = insurance_expiry {
105→                    if expiry < req.end_time {
106→                        reasons.push(ConflictReason::ExpiredInsurance {
107→                            expiry_date: expiry,
108→                        });
109→                    }
110→                }
111→
112→                // Optimistic concurrency: attempt version update
113→                let updated = conn.execute(
114→                    "UPDATE vehicles SET version = version + 1 WHERE id = ?1 AND version = ?2",
115→                    rusqlite::params![req.asset_id, version],
116→                ).unwrap_or(0);
117→
118→                if updated == 0 {
119→                    let _ = conn.execute("ROLLBACK", []);
120→                    return Err(ConflictType::VersionConflict);
121→                }
122→            }
123→            Err(_) => {
124→                let _ = conn.execute("ROLLBACK", []);
125→                return Err(ConflictType::BusinessConflict(make_validation_conflict(
126→                    "Vehicle not found",
127→                )));
128→            }
129→        }
130→    } else if req.asset_type == "bay" {
131→        // Check bay capacity
132→        let bay_row: Result<(i64, i64), _> = conn.query_row(
133→            "SELECT capacity, version FROM service_bays WHERE id = ?1",
134→            [&req.asset_id],
135→            |row| Ok((row.get(0)?, row.get(1)?)),
136→        );
137→
138→        match bay_row {
139→            Ok((capacity, version)) => {
140→                let overlapping_count: i64 = conn
141→                    .query_row(
142→                        "SELECT COUNT(*) FROM reservations WHERE asset_type = 'bay' AND asset_id = ?1 AND status = 'confirmed' AND start_time < ?3 AND end_time > ?2",
143→                        rusqlite::params![req.asset_id, req.start_time, req.end_time],
144→                        |row| row.get(0),
145→                    )
146→                    .unwrap_or(0);
147→
148→                if overlapping_count >= capacity {
149→                    reasons.push(ConflictReason::CapacityExceeded {
150→                        current: overlapping_count,
151→                        max: capacity,
152→                    });
153→                }
154→
155→                let updated = conn.execute(
156→                    "UPDATE service_bays SET version = version + 1 WHERE id = ?1 AND version = ?2",
157→                    rusqlite::params![req.asset_id, version],
158→                ).unwrap_or(0);
159→
160→                if updated == 0 {
161→                    let _ = conn.execute("ROLLBACK", []);
162→                    return Err(ConflictType::VersionConflict);
163→                }
164→            }
165→            Err(_) => {
166→                let _ = conn.execute("ROLLBACK", []);
167→                return Err(ConflictType::BusinessConflict(make_validation_conflict(
168→                    "Service bay not found",
169→                )));
170→            }
171→        }
172→    }
173→
174→    // Check overlapping reservations
175→    let overlapping: Vec<(String, String)> = {
176→        let mut stmt = conn.prepare(
177→            "SELECT start_time, end_time FROM reservations WHERE asset_type = ?1 AND asset_id = ?2 AND status = 'confirmed' AND start_time < ?4 AND end_time > ?3"
178→        ).unwrap();
179→        stmt.query_map(
180→            rusqlite::params![req.asset_type, req.asset_id, req.start_time, req.end_time],
181→            |row| Ok((row.get(0)?, row.get(1)?)),
182→        )
183→        .unwrap()
184→        .filter_map(|r| r.ok())
185→        .collect()
186→    };
187→
188→    for (existing_start, existing_end) in &overlapping {
189→        reasons.push(ConflictReason::OverlappingReservation {
190→            existing_start: existing_start.clone(),
191→            existing_end: existing_end.clone(),
192→        });
193→    }
194→
195→    if !reasons.is_empty() {
196→        let _ = conn.execute("ROLLBACK", []);
197→        return Err(ConflictType::BusinessConflict(
198→            compute_conflict_response(conn, req),
199→        ));
200→    }
201→
202→    // Create reservation
203→    let reservation_id = uuid::Uuid::new_v4().to_string();
204→    conn.execute(
205→        "INSERT INTO reservations (id, asset_type, asset_id, store_id, user_id, start_time, end_time, status) VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, 'confirmed')",
206→        rusqlite::params![reservation_id, req.asset_type, req.asset_id, req.store_id, user_id, req.start_time, req.end_time],
207→    ).map_err(|_| {
208→        let _ = conn.execute("ROLLBACK", []);
209→        ConflictType::VersionConflict
210→    })?;
211→
212→    // Generate ticket
213→    let ticket = crate::services::ticket_engine::generate_ticket(
214→        conn,
215→        &reservation_id,
216→        &req.start_time,
217→        &req.end_time,
218→    ).map_err(|_| {
219→        let _ = conn.execute("ROLLBACK", []);
220→        ConflictType::VersionConflict
221→    })?;
222→
223→    // Update reservation with ticket_id
224→    conn.execute(
225→        "UPDATE reservations SET ticket_id = ?1 WHERE id = ?2",
226→        rusqlite::params![ticket.id, reservation_id],
227→    ).map_err(|_| {
228→        let _ = conn.execute("ROLLBACK", []);
229→        ConflictType::VersionConflict
230→    })?;
231→
232→    conn.execute("COMMIT", []).map_err(|_| ConflictType::VersionConflict)?;
233→
234→    // Audit log
235→    let _ = append_audit_log(
236→        conn, user_id, username, "CREATE", "reservation", &reservation_id,
237→        &serde_json::json!({
238→            "asset_type": req.asset_type,
239→            "asset_id": req.asset_id,
240→            "start_time": req.start_time,
241→            "end_time": req.end_time,
242→            "ticket_number": ticket.ticket_number,
243→        }),
244→    );
245→
246→    let reservation = Reservation {
247→        id: reservation_id,
248→        asset_type: req.asset_type.clone(),
249→        asset_id: req.asset_id.clone(),
250→        store_id: req.store_id.clone(),
251→        user_id: user_id.to_string(),
252→        start_time: req.start_time.clone(),
253→        end_time: req.end_time.clone(),
254→        status: "confirmed".to_string(),
255→        ticket_id: Some(ticket.id.clone()),
256→        version: 1,
257→    };
258→
259→    Ok(ReservationResult { reservation, ticket })
260→}
