262→fn compute_conflict_response(conn: &Connection, req: &CreateReservationRequest) -> ConflictResponse {
263→    let mut reasons: Vec<ConflictReasonDisplay> = Vec::new();
264→
265→    // Re-check conflicts from current committed snapshot
266→    if req.asset_type == "vehicle" {
267→        if let Ok((status, insurance_expiry)) = conn.query_row(
268→            "SELECT status, insurance_expiry FROM vehicles WHERE id = ?1",
269→            [&req.asset_id],
270→            |row| Ok((row.get::<_, String>(0)?, row.get::<_, Option<String>>(1)?)),
271→        ) {
272→            if status == "in-repair" {
273→                let r = ConflictReason::InRepairHold;
274→                reasons.push(ConflictReasonDisplay {
275→                    code: r.code().to_string(),
276→                    message: r.to_message(),
277→                });
278→            }
279→            if let Some(expiry) = insurance_expiry {
280→                if expiry < req.end_time {
281→                    let r = ConflictReason::ExpiredInsurance { expiry_date: expiry };
282→                    reasons.push(ConflictReasonDisplay {
283→                        code: r.code().to_string(),
284→                        message: r.to_message(),
285→                    });
286→                }
287→            }
288→        }
289→    }
290→
291→    if req.asset_type == "bay" {
292→        if let Ok((capacity,)) = conn.query_row(
293→            "SELECT capacity FROM service_bays WHERE id = ?1",
294→            [&req.asset_id],
295→            |row| Ok((row.get::<_, i64>(0)?,)),
296→        ) {
297→            let count: i64 = conn
298→                .query_row(
299→                    "SELECT COUNT(*) FROM reservations WHERE asset_type = 'bay' AND asset_id = ?1 AND status = 'confirmed' AND start_time < ?3 AND end_time > ?2",
300→                    rusqlite::params![req.asset_id, req.start_time, req.end_time],
301→                    |row| row.get(0),
302→                )
303→                .unwrap_or(0);
304→            if count >= capacity {
305→                let r = ConflictReason::CapacityExceeded { current: count, max: capacity };
306→                reasons.push(ConflictReasonDisplay {
307→                    code: r.code().to_string(),
308→                    message: r.to_message(),
309→                });
310→            }
311→        }
312→    }
313→
314→    // Check overlapping
315→    let mut stmt = conn.prepare(
316→        "SELECT start_time, end_time FROM reservations WHERE asset_type = ?1 AND asset_id = ?2 AND status = 'confirmed' AND start_time < ?4 AND end_time > ?3"
317→    ).unwrap();
318→    let overlapping: Vec<(String, String)> = stmt
319→        .query_map(
320→            rusqlite::params![req.asset_type, req.asset_id, req.start_time, req.end_time],
321→            |row| Ok((row.get(0)?, row.get(1)?)),
322→        )
323→        .unwrap()
324→        .filter_map(|r| r.ok())
325→        .collect();
326→
327→    for (s, e) in overlapping {
328→        let r = ConflictReason::OverlappingReservation { existing_start: s, existing_end: e };
329→        reasons.push(ConflictReasonDisplay {
330→            code: r.code().to_string(),
331→            message: r.to_message(),
332→        });
333→    }
334→
335→    // Find alternative slots
336→    let alternative_slots = find_nearest_alternative_slots(conn, req);
337→    let alternate_assets = find_alternate_assets(conn, req);
338→
339→    ConflictResponse {
340→        conflict: true,
341→        reasons,
342→        alternative_slots,
343→        alternate_assets,
344→    }
345→}
