347→fn find_nearest_alternative_slots(
348→    conn: &Connection,
349→    req: &CreateReservationRequest,
350→) -> Vec<AlternativeSlot> {
351→    let duration_minutes = {
352→        let start = NaiveDateTime::parse_from_str(&req.start_time, "%Y-%m-%dT%H:%M:%S");
353→        let end = NaiveDateTime::parse_from_str(&req.end_time, "%Y-%m-%dT%H:%M:%S");
354→        match (start, end) {
355→            (Ok(s), Ok(e)) => (e - s).num_minutes(),
356→            _ => 60,
357→        }
358→    };
359→
360→    let store_start: String = conn
361→        .query_row("SELECT business_hours_start FROM stores WHERE id = ?1", [&req.store_id], |r| r.get(0))
362→        .unwrap_or_else(|_| "07:00".to_string());
363→    let store_end: String = conn
364→        .query_row("SELECT business_hours_end FROM stores WHERE id = ?1", [&req.store_id], |r| r.get(0))
365→        .unwrap_or_else(|_| "19:00".to_string());
366→
367→    let date = &req.start_time[..10]; // YYYY-MM-DD
368→    let day_start = format!("{}T{}:00", date, store_start);
369→    let day_end = format!("{}T{}:00", date, store_end);
370→
371→    let existing: Vec<(String, String)> = {
372→        let mut stmt = conn.prepare(
373→            "SELECT start_time, end_time FROM reservations WHERE asset_type = ?1 AND asset_id = ?2 AND status = 'confirmed' AND start_time >= ?3 AND end_time <= ?4 ORDER BY start_time"
374→        ).unwrap();
375→        stmt.query_map(
376→            rusqlite::params![req.asset_type, req.asset_id, day_start, day_end],
377→            |row| Ok((row.get(0)?, row.get(1)?)),
378→        ).unwrap().filter_map(|r| r.ok()).collect()
379→    };
380→
381→    let mut slots = Vec::new();
382→    let mut cursor = NaiveDateTime::parse_from_str(&day_start, "%Y-%m-%dT%H:%M:%S").unwrap();
383→    let end_of_day = NaiveDateTime::parse_from_str(&day_end, "%Y-%m-%dT%H:%M:%S").unwrap();
384→    let requested_start = NaiveDateTime::parse_from_str(&req.start_time, "%Y-%m-%dT%H:%M:%S").unwrap_or(cursor);
385→
386→    while cursor + chrono::Duration::minutes(duration_minutes) <= end_of_day {
387→        let slot_end = cursor + chrono::Duration::minutes(duration_minutes);
388→        let slot_start_str = cursor.format("%Y-%m-%dT%H:%M:%S").to_string();
389→        let slot_end_str = slot_end.format("%Y-%m-%dT%H:%M:%S").to_string();
390→
391→        let conflicts_with_existing = existing.iter().any(|(es, ee)| {
392→            slot_start_str < *ee && slot_end_str > *es
393→        });
394→
395→        if !conflicts_with_existing && slot_start_str != req.start_time {
396→            let distance = (cursor - requested_start).num_minutes().unsigned_abs();
397→            slots.push((distance, cursor >= requested_start, AlternativeSlot {
398→                start_time: slot_start_str,
399→                end_time: slot_end_str,
400→            }));
401→        }
402→
403→        cursor += chrono::Duration::minutes(15);
404→    }
405→
406→    // Sort: prefer future, then by distance
407→    slots.sort_by(|a, b| {
408→        b.1.cmp(&a.1) // future first
409→            .then(a.0.cmp(&b.0)) // then nearest
410→    });
411→
412→    slots.into_iter().take(2).map(|(_, _, s)| s).collect()
413→}
