415→fn find_alternate_assets(conn: &Connection, req: &CreateReservationRequest) -> Vec<AlternateAsset> {
416→    if req.asset_type == "vehicle" {
417→        let mut stmt = conn.prepare(
418→            "SELECT v.id, v.make, v.model, v.status FROM vehicles v WHERE v.store_id = ?1 AND v.id != ?2 AND v.status = 'available' AND v.id NOT IN (SELECT asset_id FROM reservations WHERE asset_type = 'vehicle' AND status = 'confirmed' AND start_time < ?4 AND end_time > ?3) LIMIT 3"
419→        ).unwrap();
420→        stmt.query_map(
421→            rusqlite::params![req.store_id, req.asset_id, req.start_time, req.end_time],
422→            |row| {
423→                let make: String = row.get(1)?;
424→                let model: String = row.get(2)?;
425→                Ok(AlternateAsset {
426→                    id: row.get(0)?,
427→                    asset_type: "vehicle".to_string(),
428→                    name: format!("{} {}", make, model),
429→                    status: row.get(3)?,
430→                })
431→            },
432→        ).unwrap().filter_map(|r| r.ok()).collect()
433→    } else {
434→        let mut stmt = conn.prepare(
435→            "SELECT b.id, b.name, b.status FROM service_bays b WHERE b.store_id = ?1 AND b.id != ?2 AND b.status = 'active' LIMIT 3"
436→        ).unwrap();
437→        stmt.query_map(
438→            rusqlite::params![req.store_id, req.asset_id],
439→            |row| Ok(AlternateAsset {
440→                id: row.get(0)?,
441→                asset_type: "bay".to_string(),
442→                name: row.get(1)?,
443→                status: row.get(2)?,
444→            }),
445→        ).unwrap().filter_map(|r| r.ok()).collect()
446→    }
447→}
