449→fn make_validation_conflict(msg: &str) -> ConflictResponse {
450→    ConflictResponse {
451→        conflict: true,
452→        reasons: vec![ConflictReasonDisplay {
453→            code: "validation".to_string(),
454→            message: msg.to_string(),
455→        }],
456→        alternative_slots: vec![],
457→        alternate_assets: vec![],
458→    }
