  9→pub async fn get_calendar(
 10→    State(state): State<AppState>,
 11→    headers: HeaderMap,
 12→    Query(params): Query<CalendarQuery>,
 13→) -> Result<Json<CalendarResponse>, AppError> {
 14→    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
 15→
 16→    // Store isolation for non-elevated roles
 17→    if let Some(ref user_store) = claims.store_id {
 18→        let role = UserRole::from_str(&claims.role).unwrap_or(UserRole::Customer);
 19→        if !matches!(role, UserRole::PlatformOps | UserRole::Administrator) && params.store_id != *user_store {
 20→            return Err(AppError::Forbidden("Access denied to this store's calendar".to_string()));
 21→        }
 22→    }
 23→
 24→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
 25→
 26→    let store = crate::repositories::stores::find_by_id(&db, &params.store_id)
 27→        .map_err(|e| AppError::Internal(e.to_string()))?
 28→        .ok_or_else(|| AppError::NotFound("Store not found".to_string()))?;
 29→
 30→    let business_hours = BusinessHours {
 31→        start: store.business_hours_start.clone(),
 32→        end: store.business_hours_end.clone(),
 33→    };
 34→
 35→    // Build time slots for the day
 36→    let slots = build_calendar_slots(&db, &params, &store)?;
 37→
 38→    // Get assets for the store
 39→    let vehicles = crate::repositories::vehicles::find_by_store(&db, &params.store_id)
 40→        .map_err(|e| AppError::Internal(e.to_string()))?;
 41→    let bays = crate::repositories::bays::find_by_store(&db, &params.store_id)
 42→        .map_err(|e| AppError::Internal(e.to_string()))?;
 43→
 44→    let mut assets: Vec<CalendarAsset> = vehicles.iter().map(|v| CalendarAsset {
 45→        id: v.id.clone(), asset_type: "vehicle".into(),
 46→        name: format!("{} {} {}", v.make, v.model, v.trim_level).trim().to_string(),
 47→        status: v.status.clone(),
 48→    }).collect();
 49→    assets.extend(bays.iter().map(|b| CalendarAsset {
 50→        id: b.id.clone(), asset_type: "bay".into(), name: b.name.clone(), status: b.status.clone(),
 51→    }));
 52→
 53→    Ok(Json(CalendarResponse {
 54→        store_id: params.store_id, business_hours,
 55→        date: params.date, view: params.view, slots, assets,
 56→    }))
