 59→fn build_calendar_slots(
 60→    db: &rusqlite::Connection,
 61→    params: &CalendarQuery,
 62→    store: &Store,
 63→) -> Result<Vec<CalendarSlot>, AppError> {
 64→    let date = &params.date;
 65→    let day_start = format!("{}T{}:00", date, store.business_hours_start);
 66→    let day_end = format!("{}T{}:00", date, store.business_hours_end);
 67→
 68→    let mut stmt = db.prepare(
 69→        "SELECT r.id, r.asset_type, r.asset_id, r.status, r.start_time, r.end_time, u.display_name FROM reservations r LEFT JOIN users u ON r.user_id = u.id WHERE r.store_id = ?1 AND r.start_time < ?3 AND r.end_time > ?2 AND r.status = 'confirmed' ORDER BY r.start_time"
 70→    ).map_err(|e| AppError::Internal(e.to_string()))?;
 71→
 72→    let reservations: Vec<(String, String, String, String, String, String, String)> = stmt.query_map(
 73→        rusqlite::params![params.store_id, day_start, day_end],
 74→        |row| Ok((row.get(0)?, row.get(1)?, row.get(2)?, row.get(3)?, row.get(4)?, row.get(5)?, row.get::<_, String>(6).unwrap_or_default())),
 75→    ).map_err(|e| AppError::Internal(e.to_string()))?.filter_map(|r| r.ok()).collect();
 76→
 77→    let start = chrono::NaiveDateTime::parse_from_str(&day_start, "%Y-%m-%dT%H:%M:%S")
 78→        .map_err(|_| AppError::Internal("Invalid time".into()))?;
 79→    let end = chrono::NaiveDateTime::parse_from_str(&day_end, "%Y-%m-%dT%H:%M:%S")
 80→        .map_err(|_| AppError::Internal("Invalid time".into()))?;
 81→
 82→    let mut slots = Vec::new();
 83→    let mut cursor = start;
 84→    while cursor < end {
 85→        let slot_time = cursor.format("%Y-%m-%dT%H:%M:%S").to_string();
 86→        let slot_end = (cursor + chrono::Duration::minutes(15)).format("%Y-%m-%dT%H:%M:%S").to_string();
 87→
 88→        let slot_reservations: Vec<CalendarReservation> = reservations.iter()
 89→            .filter(|(_, _, _, _, rs, re, _)| *rs < slot_end && *re > slot_time)
 90→            .map(|(id, at, aid, status, _, _, uname)| CalendarReservation {
 91→                id: id.clone(), asset_type: at.clone(), asset_id: aid.clone(),
 92→                asset_name: aid.clone(), user_display_name: uname.clone(), status: status.clone(),
 93→            }).collect();
 94→
 95→        slots.push(CalendarSlot {
 96→            time: slot_time, duration_minutes: 15, reservations: slot_reservations,
 97→        });
 98→        cursor += chrono::Duration::minutes(15);
 99→    }
100→
101→    Ok(slots)
102→}
