/// Generates a simple QR-code-like SVG data URI from ticket data.
/// This is a minimal QR representation using a deterministic grid pattern
/// derived from the ticket data hash, suitable for display purposes.
/// For production scanning, a full QR encoder (e.g. qrcode crate) should be used.
fn generate_qr_svg(data: &str) -> String {
    // Create a deterministic bit pattern from the data using a simple hash
    let mut hash_bytes: Vec<u8> = Vec::new();
    let mut h: u32 = 5381;
    for b in data.bytes() {
        h = h.wrapping_mul(33).wrapping_add(b as u32);
        if hash_bytes.len() < 441 { // 21x21 modules
            hash_bytes.push((h & 0xFF) as u8);
        }
    }
    // Pad to fill 21x21
    while hash_bytes.len() < 441 {
        h = h.wrapping_mul(33).wrapping_add(hash_bytes.len() as u32);
        hash_bytes.push((h & 0xFF) as u8);
    }

    let size = 21;
    let module_size = 8;
    let total = size * module_size;
    let mut svg = format!(
        r#"<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 {t} {t}" width="200" height="200"><rect width="{t}" height="{t}" fill="white"/>"#,
        t = total
    );

    // Draw finder patterns (3 corners)
    let draw_finder = |svg: &mut String, x: usize, y: usize| {
        for dy in 0..7 {
            for dx in 0..7 {
                let is_dark = dy == 0 || dy == 6 || dx == 0 || dx == 6
                    || (dy >= 2 && dy <= 4 && dx >= 2 && dx <= 4);
                if is_dark {
                    svg.push_str(&format!(
                        r#"<rect x="{}" y="{}" width="{}" height="{}" fill="black"/>"#,
                        (x + dx) * module_size,
                        (y + dy) * module_size,
                        module_size,
                        module_size,
                    ));
                }
            }
        }
    };

    draw_finder(&mut svg, 0, 0);
    draw_finder(&mut svg, size - 7, 0);
    draw_finder(&mut svg, 0, size - 7);

    // Draw data modules
    for row in 0..size {
        for col in 0..size {
            // Skip finder pattern areas
            if (row < 8 && col < 8) || (row < 8 && col >= size - 8) || (row >= size - 8 && col < 8) {
                continue;
            }
            let idx = row * size + col;
            if hash_bytes[idx] > 127 {
                svg.push_str(&format!(
                    r#"<rect x="{}" y="{}" width="{}" height="{}" fill="black"/>"#,
                    col * module_size,
                    row * module_size,
                    module_size,
                    module_size,
                ));
            }
        }
    }

    svg.push_str("</svg>");
    let encoded = base64_encode(&svg);
    format!("data:image/svg+xml;base64,{}", encoded)
}

fn base64_encode(input: &str) -> String {
    const CHARS: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    let bytes = input.as_bytes();
    let mut result = String::new();
    let mut i = 0;
    while i < bytes.len() {
        let b0 = bytes[i] as u32;
        let b1 = if i + 1 < bytes.len() { bytes[i + 1] as u32 } else { 0 };
        let b2 = if i + 2 < bytes.len() { bytes[i + 2] as u32 } else { 0 };
        let triple = (b0 << 16) | (b1 << 8) | b2;
        result.push(CHARS[((triple >> 18) & 0x3F) as usize] as char);
        result.push(CHARS[((triple >> 12) & 0x3F) as usize] as char);
        if i + 1 < bytes.len() { result.push(CHARS[((triple >> 6) & 0x3F) as usize] as char); } else { result.push('='); }
        if i + 2 < bytes.len() { result.push(CHARS[(triple & 0x3F) as usize] as char); } else { result.push('='); }
        i += 3;
    }
    result
}

#[component]
pub fn TicketDisplay(
    ticket: serde_json::Value,
) -> impl IntoView {
    let number = ticket.get("ticket_number").and_then(|v| v.as_str()).unwrap_or("").to_string();
    let valid_from = ticket.get("valid_from").and_then(|v| v.as_str()).unwrap_or("").to_string();
    let valid_until = ticket.get("valid_until").and_then(|v| v.as_str()).unwrap_or("").to_string();
    let redeemed = ticket.get("redeemed").and_then(|v| v.as_bool()).unwrap_or(false);
    let qr_data = ticket.get("qr_data").and_then(|v| v.as_str()).unwrap_or("").to_string();

    let qr_src = generate_qr_svg(&qr_data);

    view! {
        <div class="ticket-display">
            <img src=qr_src alt="QR Code" style="width: 200px; height: 200px; margin: 1rem auto; display: block;" />
            <div class="ticket-number">{number}</div>
            <div class="validity-window">
                "Valid: " {crate::utils::format::format_datetime(&valid_from)}
                " - " {crate::utils::format::format_datetime(&valid_until)}
            </div>
            <div style="margin-top: 0.5rem;">
                {if redeemed {
                    view! { <span class="badge" style="background: #fef3c7; color: #92400e;">"REDEEMED"</span> }.into_view()
                } else {
                    view! { <span class="badge badge-available">"VALID"</span> }.into_view()
                }}
            </div>
        </div>
    }
}
"}

