/// Generates a deterministic QR-like SVG data URI from ticket data.
/// Uses a hash-based grid with proper QR finder patterns.
/// For production camera scanning, integrate a full QR encoder crate.
fn generate_qr_svg(data: &str) -> String {
    let mut hash_vals: Vec<u8> = Vec::new();
    let mut h: u32 = 5381;
    for b in data.bytes() {
        h = h.wrapping_mul(33).wrapping_add(b as u32);
    }
    for i in 0..441u32 {
        h = h.wrapping_mul(33).wrapping_add(i);
        hash_vals.push((h & 0xFF) as u8);
    }

    let size = 21;
    let m = 8; // module pixel size
    let total = size * m;
    let mut svg = format!(
        r#"<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 {} {}" width="200" height="200"><rect width="{}" height="{}" fill="white"/>"#,
        total, total, total, total
    );

    let draw_finder = |svg: &mut String, ox: usize, oy: usize| {
        for dy in 0..7usize {
            for dx in 0..7usize {
                let dark = dy == 0 || dy == 6 || dx == 0 || dx == 6
                    || (dy >= 2 && dy <= 4 && dx >= 2 && dx <= 4);
                if dark {
                    svg.push_str(&format!(
                        r#"<rect x="{}" y="{}" width="{}" height="{}" fill="black"/>"#,
                        (ox + dx) * m, (oy + dy) * m, m, m
                    ));
                }
            }
        }
    };
    draw_finder(&mut svg, 0, 0);
    draw_finder(&mut svg, size - 7, 0);
    draw_finder(&mut svg, 0, size - 7);

    for row in 0..size {
        for col in 0..size {
            if (row < 8 && col < 8) || (row < 8 && col >= size - 8) || (row >= size - 8 && col < 8) {
                continue;
            }
            if hash_vals[row * size + col] > 127 {
                svg.push_str(&format!(
                    r#"<rect x="{}" y="{}" width="{}" height="{}" fill="black"/>"#,
                    col * m, row * m, m, m
                ));
            }
        }
    }
    svg.push_str("</svg>");

    // Inline base64 encode for data URI
    let encoded = simple_b64(svg.as_bytes());
    format!("data:image/svg+xml;base64,{}", encoded)
}

fn simple_b64(input: &[u8]) -> String {
    const T: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    let mut out = String::new();
    let mut i = 0;
    while i < input.len() {
        let a = input[i] as u32;
        let b = if i+1 < input.len() { input[i+1] as u32 } else { 0 };
        let c = if i+2 < input.len() { input[i+2] as u32 } else { 0 };
        let n = (a << 16) | (b << 8) | c;
        out.push(T[((n >> 18) & 63) as usize] as char);
        out.push(T[((n >> 12) & 63) as usize] as char);
        out.push(if i+1 < input.len() { T[((n >> 6) & 63) as usize] as char } else { '=' });
        out.push(if i+2 < input.len() { T[(n & 63) as usize] as char } else { '=' });
        i += 3;
    }
    out
}

