 16→/// Auth middleware that rejects unauthenticated requests
 17→async fn require_auth(
 18→    State(state): State<AppState>,
 19→    request: Request<axum::body::Body>,
 20→    next: Next,
 21→) -> Result<Response, StatusCode> {
 22→    let auth_header = request
 23→        .headers()
 24→        .get("authorization")
 25→        .and_then(|v| v.to_str().ok())
 26→        .unwrap_or("");
 27→
 28→    if let Some(token) = auth_header.strip_prefix("Bearer ") {
 29→        if crate::auth::session::validate_token(token, &state.hmac_secret).is_some() {
 30→            return Ok(next.run(request).await);
 31→        }
 32→    }
 33→
 34→    Err(StatusCode::UNAUTHORIZED)
 35→}
