 37→/// Auth middleware that requires MerchantStaff or higher role
 38→async fn require_staff(
 39→    State(state): State<AppState>,
 40→    request: Request<axum::body::Body>,
 41→    next: Next,
 42→) -> Result<Response, StatusCode> {
 43→    let claims = request
 44→        .headers()
 45→        .get("authorization")
 46→        .and_then(|v| v.to_str().ok())
 47→        .and_then(|h| h.strip_prefix("Bearer "))
 48→        .and_then(|t| crate::auth::session::validate_token(t, &state.hmac_secret));
 49→
 50→    match claims {
 51→        Some(c) => {
 52→            let role = crate::models::UserRole::from_str(&c.role);
 53→            if role.map_or(false, |r| r.has_at_least(&crate::models::UserRole::MerchantStaff)) {
 54→                Ok(next.run(request).await)
 55→            } else {
 56→                Err(StatusCode::FORBIDDEN)
 57→            }
 58→        }
 59→        None => Err(StatusCode::UNAUTHORIZED),
 60→    }
