111→        .map_err(|e| AppError::Internal(e.to_string()))?
112→        .ok_or_else(|| AppError::Validation("Invalid username or recovery code".to_string()))?;
113→
114→    let code_hash = hash_recovery_code(&req.recovery_code);
115→    let rc = crate::repositories::recovery_codes::find_valid(&db, &user.id, &code_hash)
116→        .map_err(|e| AppError::Internal(e.to_string()))?
117→        .ok_or_else(|| AppError::Validation("Invalid or expired recovery code".to_string()))?;
118→
119→    let new_hash = password::hash_password(&req.new_password)
120→        .map_err(|e| AppError::Internal(e))?;
121→    crate::repositories::users::update_password(&db, &user.id, &new_hash)
122→        .map_err(|e| AppError::Internal(e.to_string()))?;
123→    crate::repositories::recovery_codes::mark_used(&db, &rc.id)
124→        .map_err(|e| AppError::Internal(e.to_string()))?;
125→
126→    let _ = crate::audit::chain::append_audit_log(
127→        &db, &user.id, &user.username, "PASSWORD_RESET", "user", &user.id,
128→        &serde_json::json!({"method": "recovery_code"}),
