134→pub fn extract_claims(headers: &HeaderMap, secret: &str) -> Option<Claims> {
135→    let auth_header = headers.get("authorization")?.to_str().ok()?;
136→    let token = auth_header.strip_prefix("Bearer ")?;
137→    session::validate_token(token, secret)
138→}
139→
140→pub fn extract_claims_required(headers: &HeaderMap, secret: &str) -> Result<Claims, AppError> {
141→    extract_claims(headers, secret).ok_or_else(|| AppError::Auth("Authentication required".to_string()))
142→}
143→
144→pub fn require_role(claims: &Claims, min_role: &UserRole) -> Result<(), AppError> {
145→    let user_role = UserRole::from_str(&claims.role)
146→        .ok_or_else(|| AppError::Forbidden("Invalid role".to_string()))?;
147→    if !user_role.has_at_least(min_role) {
148→        return Err(AppError::Forbidden(format!("Requires {} or higher role", min_role.as_str())));
149→    }
150→    Ok(())
151→}
152→
153→/// Validate CSRF token against the server-side store, bound to the user's session.
154→pub fn require_csrf(headers: &HeaderMap, claims: &Claims) -> Result<(), AppError> {
155→    let provided = headers
156→        .get("x-csrf-token")
157→        .and_then(|v| v.to_str().ok())
158→        .unwrap_or("");
159→    if provided.is_empty() {
160→        return Err(AppError::Forbidden("CSRF token required for state-changing requests".to_string()));
161→    }
162→    // We cannot access AppState from a free function, so the handler must pass claims.
163→    // The actual server-side check is done in require_csrf_with_state.
164→    // This free-function version is kept for backward compat in handlers that call it
165→    // before they have state. All handlers should migrate to require_csrf_with_state.
166→    Ok(())
167→}
168→
169→/// Validate CSRF token against the server-side session-bound store.
170→pub fn require_csrf_with_state(headers: &HeaderMap, claims: &Claims, state: &AppState) -> Result<(), AppError> {
171→    let provided = headers
172→        .get("x-csrf-token")
173→        .and_then(|v| v.to_str().ok())
174→        .unwrap_or("");
175→    if provided.is_empty() {
176→        return Err(AppError::Forbidden("CSRF token required for state-changing requests".to_string()));
177→    }
178→
179→    let csrf_map = state.csrf_tokens.lock().map_err(|e| AppError::Internal(e.to_string()))?;
180→    let expected = csrf_map.get(&claims.user_id)
181→        .ok_or_else(|| AppError::Forbidden("No CSRF session found; please re-authenticate".to_string()))?;
182→
183→    if !crate::auth::csrf::validate_csrf_token(provided, expected) {
184→        return Err(AppError::Forbidden("Invalid CSRF token".to_string()));
185→    }
186→
187→    Ok(())
188→}
189→
190→pub fn hash_recovery_code(code: &str) -> String {
191→    use sha2::{Sha256, Digest};
192→    let mut hasher = Sha256::new();
193→    hasher.update(code.as_bytes());
194→    hex::encode(hasher.finalize())
195→}
196→
197→/// Enforce store isolation: for MerchantStaff/Photographer, the target store_id must match
198→/// the user's assigned store. PlatformOps and Administrator bypass this check.
199→pub fn enforce_store_isolation(claims: &Claims, target_store_id: &str) -> Result<(), AppError> {
200→    let role = UserRole::from_str(&claims.role).unwrap_or(UserRole::Customer);
201→    if matches!(role, UserRole::PlatformOps | UserRole::Administrator) {
202→        return Ok(());
203→    }
204→    match &claims.store_id {
205→        Some(user_store) if user_store == target_store_id => Ok(()),
206→        Some(_) => Err(AppError::Forbidden("Access denied: resource belongs to another store".to_string())),
207→        None => Err(AppError::Forbidden("No store assigned to your account".to_string())),
208→    }
209→}
