 3→
 4→pub fn create(conn: &Connection, rc: &RecoveryCode) -> Result<(), rusqlite::Error> {
 5→    // Invalidate existing unused codes for this user
 6→    conn.execute(
 7→        "UPDATE recovery_codes SET used = 1, used_at = datetime('now') WHERE user_id = ?1 AND used = 0",
 8→        [&rc.user_id],
 9→    )?;
10→    conn.execute(
11→        "INSERT INTO recovery_codes (id, user_id, code_hash, issued_by, expires_at) VALUES (?1,?2,?3,?4,?5)",
12→        rusqlite::params![rc.id, rc.user_id, rc.code_hash, rc.issued_by, rc.expires_at],
13→    )?;
14→    Ok(())
15→}
16→
17→pub fn find_valid(conn: &Connection, user_id: &str, code_hash: &str) -> Result<Option<RecoveryCode>, rusqlite::Error> {
18→    match conn.query_row(
19→        "SELECT id, user_id, code_hash, issued_by, issued_at, expires_at, used FROM recovery_codes WHERE user_id = ?1 AND code_hash = ?2 AND used = 0 AND expires_at > datetime('now')",
20→        rusqlite::params![user_id, code_hash],
21→        |row| Ok(RecoveryCode {
22→            id: row.get(0)?, user_id: row.get(1)?, code_hash: row.get(2)?,
23→            issued_by: row.get(3)?, issued_at: row.get(4)?, expires_at: row.get(5)?,
24→            used: row.get::<_, i64>(6)? != 0,
25→        }),
26→    ) {
27→        Ok(rc) => Ok(Some(rc)),
28→        Err(rusqlite::Error::QueryReturnedNoRows) => Ok(None),
29→        Err(e) => Err(e),
30→    }
31→}
