 96→pub async fn issue_recovery_code(
 97→    State(state): State<AppState>,
 98→    headers: HeaderMap,
 99→    Json(req): Json<IssueRecoveryCodeRequest>,
100→) -> Result<Json<serde_json::Value>, AppError> {
101→    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
102→    require_role(&claims, &UserRole::Administrator)?;
103→    require_csrf_with_state(&headers, &claims, &state)?;
104→
105→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
106→
107→    // Verify target user exists
108→    let _user = crate::repositories::users::find_by_id(&db, &req.user_id)
109→        .map_err(|e| AppError::Internal(e.to_string()))?
110→        .ok_or_else(|| AppError::NotFound("User not found".to_string()))?;
111→
112→    // Generate recovery code
113→    let code: String = {
114→        use rand::Rng;
115→        let mut rng = rand::thread_rng();
116→        (0..12).map(|_| {
117→            let idx = rng.gen_range(0..36);
118→            if idx < 10 { (b'0' + idx) as char } else { (b'A' + idx - 10) as char }
119→        }).collect()
120→    };
121→
122→    let code_hash = hash_recovery_code(&code);
123→    let expires_at = (chrono::Utc::now() + chrono::Duration::minutes(30))
124→        .format("%Y-%m-%dT%H:%M:%SZ").to_string();
125→
126→    let rc = RecoveryCode {
127→        id: uuid::Uuid::new_v4().to_string(),
128→        user_id: req.user_id.clone(),
129→        code_hash,
130→        issued_by: claims.user_id.clone(),
131→        issued_at: chrono::Utc::now().format("%Y-%m-%dT%H:%M:%SZ").to_string(),
132→        expires_at: expires_at.clone(),
133→        used: false,
134→    };
135→
136→    crate::repositories::recovery_codes::create(&db, &rc).map_err(|e| AppError::Internal(e.to_string()))?;
137→
138→    let _ = crate::audit::chain::append_audit_log(
139→        &db, &claims.user_id, &claims.username, "CREATE", "recovery_code", &rc.id,
140→        &serde_json::json!({"target_user_id": req.user_id}),
141→    );
142→
143→    Ok(Json(serde_json::json!({
144→        "code": code,
145→        "expires_at": expires_at,
146→    })))
147→}
