 3→
 4→use fleetreserve_backend::app::state::AppState;
 5→use fleetreserve_backend::routes;
 6→
 7→#[tokio::main]
 8→async fn main() {
 9→    tracing_subscriber::registry()
10→        .with(EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info")))
11→        .with(tracing_subscriber::fmt::layer())
12→        .init();
13→
14→    tracing::info!("Starting FleetReserve Operations Suite backend");
15→
16→    let db_url = std::env::var("DATABASE_URL").unwrap_or_else(|_| "fleetreserve.db".to_string());
17→    let conn = rusqlite::Connection::open(&db_url).expect("Failed to open database");
18→    conn.execute_batch("PRAGMA journal_mode=WAL; PRAGMA foreign_keys=ON;")
19→        .expect("Failed to set pragmas");
20→
21→    run_migrations(&conn);
22→
23→    let encryption_key = std::env::var("ENCRYPTION_KEY")
24→        .unwrap_or_else(|_| "default-change-me-32-byte-key!!".to_string());
25→    let hmac_secret = std::env::var("HMAC_SECRET")
26→        .unwrap_or_else(|_| "default-hmac-secret-change-me!!!".to_string());
27→    let upload_dir = std::env::var("UPLOAD_DIR").unwrap_or_else(|_| "./uploads".to_string());
28→
29→    std::fs::create_dir_all(&upload_dir).expect("Failed to create upload directory");
30→
31→    let state = AppState {
32→        db: Arc::new(Mutex::new(conn)),
33→        encryption_key,
34→        hmac_secret,
35→        upload_dir,
36→        csrf_tokens: Arc::new(Mutex::new(std::collections::HashMap::new())),
37→    };
38→
39→    let app = routes::build_router(state);
40→
41→    let addr = "0.0.0.0:3001";
42→    tracing::info!("Listening on {}", addr);
43→    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
44→    axum::serve(listener, app).await.unwrap();
45→}
