 1→use crate::audit::chain::append_audit_log;
 2→use crate::models::*;
 3→use chrono::NaiveDateTime;
 4→use rusqlite::Connection;
 5→
 6→const MAX_RETRIES: u32 = 3;
 7→
 8→pub struct ReservationResult {
 9→    pub reservation: Reservation,
10→    pub ticket: Ticket,
11→}
12→
13→pub fn create_reservation(
14→    conn: &Connection,
15→    user_id: &str,
16→    username: &str,
17→    req: &CreateReservationRequest,
18→) -> Result<ReservationResult, ConflictResponse> {
19→    let start = NaiveDateTime::parse_from_str(&req.start_time, "%Y-%m-%dT%H:%M:%S")
20→        .or_else(|_| NaiveDateTime::parse_from_str(&req.start_time, "%Y-%m-%dT%H:%M"))
21→        .map_err(|_| make_validation_conflict("Invalid start_time format (expected YYYY-MM-DDTHH:MM:SS or YYYY-MM-DDTHH:MM)"))?;
22→    let end = NaiveDateTime::parse_from_str(&req.end_time, "%Y-%m-%dT%H:%M:%S")
23→        .or_else(|_| NaiveDateTime::parse_from_str(&req.end_time, "%Y-%m-%dT%H:%M"))
24→        .map_err(|_| make_validation_conflict("Invalid end_time format (expected YYYY-MM-DDTHH:MM:SS or YYYY-MM-DDTHH:MM)"))?;
25→
26→    if end <= start {
27→        return Err(make_validation_conflict("end_time must be after start_time"));
28→    }
29→
30→    // Validate within business hours
31→    let store_start: String = conn
32→        .query_row(
33→            "SELECT business_hours_start FROM stores WHERE id = ?1",
34→            [&req.store_id],
35→            |row| row.get(0),
36→        )
37→        .unwrap_or_else(|_| "07:00".to_string());
38→    let store_end: String = conn
39→        .query_row(
40→            "SELECT business_hours_end FROM stores WHERE id = ?1",
41→            [&req.store_id],
42→            |row| row.get(0),
43→        )
44→        .unwrap_or_else(|_| "19:00".to_string());
45→
46→    let start_time_str = start.format("%H:%M").to_string();
47→    let end_time_str = end.format("%H:%M").to_string();
48→    if start_time_str < store_start || end_time_str > store_end {
49→        return Err(make_validation_conflict("Reservation must be within business hours"));
50→    }
51→
52→    for attempt in 0..MAX_RETRIES {
53→        match try_create_reservation(conn, user_id, username, req, attempt) {
54→            Ok(result) => return Ok(result),
55→            Err(ConflictType::VersionConflict) if attempt < MAX_RETRIES - 1 => {
56→                tracing::warn!("Reservation attempt {} failed with version conflict, retrying", attempt + 1);
57→                continue;
58→            }
59→            Err(ConflictType::VersionConflict) => {
60→                tracing::error!("Max retries exceeded for reservation");
61→                return Err(compute_conflict_response(conn, req));
62→            }
63→            Err(ConflictType::BusinessConflict(resp)) => return Err(resp),
64→        }
65→    }
66→
67→    Err(compute_conflict_response(conn, req))
68→}
69→
