 36→#[component]
 37→pub fn CheckInPage() -> impl IntoView {
 38→    let auth = use_context::<AuthState>().expect("AuthState");
 39→    let ticket_input = create_rw_signal(String::new());
 40→    let status_msg = create_rw_signal(Option::<(bool, String)>::None);
 41→    let redeemed_ticket_id = create_rw_signal(Option::<String>::None);
 42→    let undo_reason = create_rw_signal(String::new());
 43→    let undo_available = create_rw_signal(false);
 44→
 45→    let on_redeem = move |ev: leptos::ev::SubmitEvent| {
 46→        ev.prevent_default();
 47→        let input = ticket_input.get();
 48→        status_msg.set(None);
 49→
 50→        spawn_local(async move {
 51→            // Try to find ticket by number first, then by ID
 52→            let ticket_id = input.clone();
 53→            match crate::api::client::api_post(&format!("/tickets/{}/redeem", ticket_id), &serde_json::json!({})).await {
 54→                Ok((200, _)) => {
 55→                    status_msg.set(Some((true, "Ticket redeemed successfully!".into())));
 56→                    redeemed_ticket_id.set(Some(ticket_id));
 57→                    undo_available.set(true);
 58→                    // Start 2-minute timer for undo eligibility
 59→                    gloo_timers::callback::Timeout::new(120_000, move || {
 60→                        undo_available.set(false);
 61→                    }).forget();
 62→                }
 63→                Ok((_, json)) => {
 64→                    if let Ok(val) = serde_wasm_bindgen::from_value::<serde_json::Value>(json) {
 65→                        let msg = val.get("error").and_then(|e| e.get("message")).and_then(|m| m.as_str()).unwrap_or("Redemption failed");
 66→                        status_msg.set(Some((false, msg.to_string())));
 67→                    }
 68→                }
 69→                Err(e) => status_msg.set(Some((false, e))),
 70→            }
 71→        });
 72→    };
 73→
 74→    let on_undo = move |_| {
 75→        let reason = undo_reason.get();
 76→        if reason.trim().is_empty() {
 77→            status_msg.set(Some((false, "Undo reason is required".into())));
 78→            return;
 79→        }
 80→        if let Some(tid) = redeemed_ticket_id.get() {
 81→            spawn_local(async move {
 82→                match crate::api::client::api_post(&format!("/tickets/{}/undo", tid), &serde_json::json!({"reason": reason})).await {
 83→                    Ok((200, _)) => {
 84→                        status_msg.set(Some((true, "Redemption undone successfully".into())));
 85→                        undo_available.set(false);
 86→                    }
 87→                    Ok((_, json)) => {
