 1→use crate::state::auth::AuthState;
 2→use leptos::*;
 3→use wasm_bindgen::JsValue;
 4→use wasm_bindgen_futures::JsFuture;
 5→use web_sys::{Headers, Request, RequestInit, Response};
 6→
 7→pub async fn api_get(path: &str) -> Result<JsValue, String> {
 8→    let auth = use_context::<AuthState>().ok_or("No auth context")?;
 9→    let opts = RequestInit::new();
10→    opts.set_method("GET");
11→
12→    let headers = Headers::new().map_err(|e| format!("{:?}", e))?;
13→    if let Some(token) = auth.token.get_untracked() {
14→        headers.set("Authorization", &format!("Bearer {}", token)).map_err(|e| format!("{:?}", e))?;
15→    }
16→    opts.set_headers(&headers);
17→
18→    let url = format!("/api{}", path);
19→    let request = Request::new_with_str_and_init(&url, &opts).map_err(|e| format!("{:?}", e))?;
20→    let window = web_sys::window().ok_or("No window")?;
21→    let resp_value = JsFuture::from(window.fetch_with_request(&request)).await.map_err(|e| format!("{:?}", e))?;
22→    let resp: Response = resp_value.dyn_into().map_err(|_| "Not a response")?;
23→
24→    if resp.status() == 401 {
25→        auth.logout();
26→        return Err("Session expired".to_string());
27→    }
28→
29→    let json = JsFuture::from(resp.json().map_err(|e| format!("{:?}", e))?).await.map_err(|e| format!("{:?}", e))?;
30→    Ok(json)
31→}
32→
33→pub async fn api_post(path: &str, body: &serde_json::Value) -> Result<(u16, JsValue), String> {
34→    let auth = use_context::<AuthState>().ok_or("No auth context")?;
35→    let opts = RequestInit::new();
36→    opts.set_method("POST");
37→
38→    let headers = Headers::new().map_err(|e| format!("{:?}", e))?;
39→    headers.set("Content-Type", "application/json").map_err(|e| format!("{:?}", e))?;
40→    if let Some(token) = auth.token.get_untracked() {
41→        headers.set("Authorization", &format!("Bearer {}", token)).map_err(|e| format!("{:?}", e))?;
42→    }
43→    if let Some(csrf) = auth.csrf_token.get_untracked() {
44→        headers.set("X-CSRF-Token", &csrf).map_err(|e| format!("{:?}", e))?;
45→    }
46→    opts.set_headers(&headers);
47→
48→    let body_str = serde_json::to_string(body).map_err(|e| e.to_string())?;
49→    opts.set_body(&JsValue::from_str(&body_str));
50→
51→    let url = format!("/api{}", path);
52→    let request = Request::new_with_str_and_init(&url, &opts).map_err(|e| format!("{:?}", e))?;
53→    let window = web_sys::window().ok_or("No window")?;
54→    let resp_value = JsFuture::from(window.fetch_with_request(&request)).await.map_err(|e| format!("{:?}", e))?;
55→    let resp: Response = resp_value.dyn_into().map_err(|_| "Not a response")?;
56→
57→    let status = resp.status();
58→    if status == 401 {
59→        auth.logout();
60→        return Err("Session expired".to_string());
61→    }
62→
63→    let json = JsFuture::from(resp.json().map_err(|e| format!("{:?}", e))?).await.map_err(|e| format!("{:?}", e))?;
64→    Ok((status, json))
65→}
66→
67→pub async fn api_put(path: &str, body: &serde_json::Value) -> Result<(u16, JsValue), String> {
68→    let auth = use_context::<AuthState>().ok_or("No auth context")?;
