 1→use leptos::*;
 2→
 3→#[component]
 4→pub fn UploadForm(
 5→    #[prop(optional)] vehicle_id: Option<String>,
 6→) -> impl IntoView {
 7→    let status = create_rw_signal(Option::<(bool, String)>::None);
 8→    let file_name = create_rw_signal(String::new());
 9→
10→    let on_file_change = move |ev: leptos::ev::Event| {
11→        let input: web_sys::HtmlInputElement = event_target(&ev);
12→        if let Some(files) = input.files() {
13→            if let Some(file) = files.get(0) {
14→                let name = file.name();
15→                let size = file.size() as usize;
16→                if size > 10 * 1024 * 1024 {
17→                    status.set(Some((false, "File exceeds 10 MB limit".into())));
18→                    return;
19→                }
20→                let ext = name.rsplit('.').next().unwrap_or("").to_lowercase();
21→                if ext != "jpg" && ext != "jpeg" && ext != "png" {
22→                    status.set(Some((false, "Only JPEG and PNG files are accepted".into())));
23→                    return;
24→                }
25→                file_name.set(name);
26→                status.set(Some((true, "File selected, ready to upload".into())));
27→            }
28→        }
29→    };
30→
31→    view! {
32→        <div class="form-group">
33→            <label>"Upload Photo (JPEG/PNG, max 10 MB)"</label>
34→            <input type="file" accept="image/jpeg,image/png" on:change=on_file_change />
35→        </div>
36→        <Show when=move || status.get().is_some()>
37→            {move || {
38→                let (ok, msg) = status.get().unwrap();
39→                view! {
40→                    <p style=format!("font-size: 0.875rem; color: {};", if ok { "#166534" } else { "#991b1b" })>
41→                        {msg}
42→                    </p>
43→                }
44→            }}
45→        </Show>
46→    }
47→}
