  9→/// Normalize datetime-local input ("2026-04-10T09:00") to full seconds format ("2026-04-10T09:00:00")
 10→fn normalize_datetime(input: &str) -> String {
 11→    if input.len() == 16 {
 12→        // "YYYY-MM-DDTHH:MM" -> "YYYY-MM-DDTHH:MM:00"
 13→        format!("{}:00", input)
 14→    } else {
 15→        input.to_string()
 16→    }
