 19→pub async fn create_reservation(
 20→    State(state): State<AppState>,
 21→    headers: HeaderMap,
 22→    Json(mut req): Json<CreateReservationRequest>,
 23→) -> Result<(axum::http::StatusCode, Json<serde_json::Value>), AppError> {
 24→    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
 25→    require_csrf_with_state(&headers, &claims, &state)?;
 26→
 27→    if req.asset_type != "vehicle" && req.asset_type != "bay" {
 28→        return Err(AppError::Validation("asset_type must be 'vehicle' or 'bay'".to_string()));
 29→    }
 30→
 31→    // Normalize datetime inputs (frontend datetime-local may omit seconds)
 32→    req.start_time = normalize_datetime(&req.start_time);
 33→    req.end_time = normalize_datetime(&req.end_time);
 34→
 35→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
 36→
 37→    // Verify the asset exists and belongs to the claimed store_id
 38→    if req.asset_type == "vehicle" {
 39→        let vehicle_store: String = db
 40→            .query_row(
 41→                "SELECT store_id FROM vehicles WHERE id = ?1",
 42→                [&req.asset_id],
 43→                |row| row.get(0),
 44→            )
 45→            .map_err(|_| AppError::NotFound("Vehicle not found".to_string()))?;
 46→        if vehicle_store != req.store_id {
 47→            return Err(AppError::Validation("Vehicle does not belong to the specified store".to_string()));
 48→        }
 49→    } else {
 50→        let bay_store: String = db
 51→            .query_row(
 52→                "SELECT store_id FROM service_bays WHERE id = ?1",
 53→                [&req.asset_id],
 54→                |row| row.get(0),
 55→            )
 56→            .map_err(|_| AppError::NotFound("Service bay not found".to_string()))?;
 57→        if bay_store != req.store_id {
 58→            return Err(AppError::Validation("Service bay does not belong to the specified store".to_string()));
 59→        }
 60→    }
 61→
 62→    // Store isolation: non-elevated roles can only create reservations in their own store
 63→    enforce_store_isolation(&claims, &req.store_id)?;
 64→
 65→    match crate::services::reservation_engine::create_reservation(&db, &claims.user_id, &claims.username, &req) {
 66→        Ok(result) => {
 67→            Ok((axum::http::StatusCode::CREATED, Json(serde_json::json!({
 68→                "reservation": result.reservation,
 69→                "ticket": result.ticket,
 70→            }))))
 71→        }
 72→        Err(conflict) => {
 73→            Ok((axum::http::StatusCode::CONFLICT, Json(serde_json::to_value(conflict).unwrap())))
 74→        }
 75→    }
 76→}
