 78→pub async fn list_reservations(
 79→    State(state): State<AppState>,
 80→    headers: HeaderMap,
 81→    Query(params): Query<std::collections::HashMap<String, String>>,
 82→) -> Result<Json<serde_json::Value>, AppError> {
 83→    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
 84→    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
 85→
 86→    let reservations = match UserRole::from_str(&claims.role) {
 87→        Some(UserRole::Customer) => {
 88→            crate::repositories::reservations::find_by_user(&db, &claims.user_id)
 89→        }
 90→        Some(UserRole::PlatformOps) | Some(UserRole::Administrator) => {
 91→            if let Some(store_id) = params.get("store_id") {
 92→                crate::repositories::reservations::find_by_store(&db, store_id)
 93→            } else {
 94→                crate::repositories::reservations::find_all(&db)
 95→            }
 96→        }
 97→        _ => {
 98→            let store_id = claims.store_id.as_deref()
 99→                .ok_or_else(|| AppError::Forbidden("No store assigned".to_string()))?;
100→            crate::repositories::reservations::find_by_store(&db, store_id)
101→        }
102→    }.map_err(|e| AppError::Internal(e.to_string()))?;
103→
104→    Ok(Json(serde_json::json!({"reservations": reservations})))
