use axum::http::HeaderMap;
use axum::Json;
use crate::app::state::AppState;
use crate::errors::AppError;
use crate::handlers::auth::*;
use crate::models::*;

/// Resolve a ticket by ID or by ticket number (FR-XXXXXXXX)
fn resolve_ticket(db: &rusqlite::Connection, id_or_number: &str) -> Result<Ticket, AppError> {
    if let Ok(Some(t)) = crate::repositories::tickets::find_by_id(db, id_or_number) {
        return Ok(t);
    }
    if let Ok(Some(t)) = crate::repositories::tickets::find_by_number(db, id_or_number) {
        return Ok(t);
    }
    Err(AppError::NotFound("Ticket not found".to_string()))
}

fn get_ticket_store(db: &rusqlite::Connection, reservation_id: &str) -> Result<String, AppError> {
    db.query_row(
        "SELECT store_id FROM reservations WHERE id = ?1",
        [reservation_id],
        |row| row.get(0),
    )
    .map_err(|_| AppError::Internal("Reservation not found for ticket".to_string()))
}

fn get_ticket_owner(db: &rusqlite::Connection, reservation_id: &str) -> Result<String, AppError> {
    db.query_row(
        "SELECT user_id FROM reservations WHERE id = ?1",
        [reservation_id],
        |row| row.get(0),
    )
    .map_err(|_| AppError::Internal("Reservation not found for ticket".to_string()))
}

pub async fn get_ticket(
    State(state): State<AppState>,
    headers: HeaderMap,
    Path(id): Path<String>,
) -> Result<Json<Ticket>, AppError> {
    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;

    let ticket = resolve_ticket(&db, &id)?;
    let ticket_store = get_ticket_store(&db, &ticket.reservation_id)?;
    let ticket_owner = get_ticket_owner(&db, &ticket.reservation_id)?;

    let role = UserRole::from_str(&claims.role).unwrap_or(UserRole::Customer);

    match role {
        UserRole::Administrator => { /* full access */ }
        UserRole::PlatformOps => { /* cross-store read access */ }
        UserRole::MerchantStaff => {
            // Staff can only see tickets from their own store
            enforce_store_isolation(&claims, &ticket_store)?;
        }
        UserRole::Customer => {
            // Customer can only see own tickets
            if ticket_owner != claims.user_id {
                return Err(AppError::Forbidden("Access denied: this is not your ticket".to_string()));
            }
        }
        UserRole::Photographer => {
            // Photographers can only see tickets for reservations on their assigned assets
            let has_assignment: bool = db.query_row(
                "SELECT COUNT(*) > 0 FROM photographer_assignments pa JOIN reservations r ON (r.asset_id = pa.vehicle_id OR r.asset_id = pa.bay_id) WHERE pa.photographer_user_id = ?1 AND r.id = ?2",
                rusqlite::params![claims.user_id, ticket.reservation_id],
                |row| row.get(0),
            ).unwrap_or(false);
            if !has_assignment {
                return Err(AppError::Forbidden("Access denied: ticket not associated with your assignments".to_string()));
            }
        }
    }

    Ok(Json(ticket))
}

pub async fn redeem_ticket(
    State(state): State<AppState>,
    headers: HeaderMap,
    Path(id): Path<String>,
) -> Result<Json<serde_json::Value>, AppError> {
    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
    require_role(&claims, &UserRole::MerchantStaff)?;
    require_csrf_with_state(&headers, &claims, &state)?;

    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
    let ticket = resolve_ticket(&db, &id)?;
    let ticket_store = get_ticket_store(&db, &ticket.reservation_id)?;
    enforce_store_isolation(&claims, &ticket_store)?;

    match crate::services::ticket_engine::redeem_ticket(&db, &ticket.id, &claims.user_id, &claims.username) {
        Ok(redeemed_at) => {
            Ok(Json(serde_json::json!({
                "message": "Ticket redeemed",
                "redeemed_at": redeemed_at,
                "ticket_number": ticket.ticket_number,
                "valid_from": ticket.valid_from,
                "valid_until": ticket.valid_until,
            })))
        }
        Err(msg) => Err(AppError::Validation(msg)),
    }
}

pub async fn undo_redemption(
    State(state): State<AppState>,
    headers: HeaderMap,
    Path(id): Path<String>,
    Json(req): Json<UndoRedemptionRequest>,
) -> Result<Json<serde_json::Value>, AppError> {
    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
    require_role(&claims, &UserRole::MerchantStaff)?;
    require_csrf_with_state(&headers, &claims, &state)?;

    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;
    let ticket = resolve_ticket(&db, &id)?;
    let ticket_store = get_ticket_store(&db, &ticket.reservation_id)?;
    enforce_store_isolation(&claims, &ticket_store)?;

    match crate::services::ticket_engine::undo_redemption(&db, &ticket.id, &claims.user_id, &claims.username, &req.reason) {
        Ok(()) => Ok(Json(serde_json::json!({"message": "Redemption undone"}))),
        Err(msg) => Err(AppError::Validation(msg)),
    }
}
"}

