use rusqlite::Connection;

pub fn create(conn: &Connection, rc: &RecoveryCode) -> Result<(), rusqlite::Error> {
    // Invalidate existing unused codes for this user
    conn.execute(
        "UPDATE recovery_codes SET used = 1, used_at = datetime('now') WHERE user_id = ?1 AND used = 0",
        [&rc.user_id],
    )?;
    conn.execute(
        "INSERT INTO recovery_codes (id, user_id, code_hash, issued_by, issued_at, expires_at) VALUES (?1,?2,?3,?4,?5,?6)",
        rusqlite::params![rc.id, rc.user_id, rc.code_hash, rc.issued_by, rc.issued_at, rc.expires_at],
    )?;
    Ok(())
}

pub fn find_valid(conn: &Connection, user_id: &str, code_hash: &str) -> Result<Option<RecoveryCode>, rusqlite::Error> {
    // Use strftime to normalize both stored expires_at and current time to epoch seconds
    // This handles any format mismatch between RFC3339/ISO8601 and SQLite datetime
    match conn.query_row(
        "SELECT id, user_id, code_hash, issued_by, issued_at, expires_at, used FROM recovery_codes WHERE user_id = ?1 AND code_hash = ?2 AND used = 0 AND strftime('%s', expires_at) > strftime('%s', 'now')",
        rusqlite::params![user_id, code_hash],
        |row| Ok(RecoveryCode {
            id: row.get(0)?, user_id: row.get(1)?, code_hash: row.get(2)?,
            issued_by: row.get(3)?, issued_at: row.get(4)?, expires_at: row.get(5)?,
            used: row.get::<_, i64>(6)? != 0,
        }),
    ) {
        Ok(rc) => Ok(Some(rc)),
        Err(rusqlite::Error::QueryReturnedNoRows) => Ok(None),
        Err(e) => Err(e),
    }
}

pub fn mark_used(conn: &Connection, id: &str) -> Result<(), rusqlite::Error> {
    conn.execute(
        "UPDATE recovery_codes SET used = 1, used_at = datetime('now') WHERE id = ?1",
        [id],
    )?;
    Ok(())
}
"}

