pub async fn create_permission(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(req): Json<serde_json::Value>,
) -> Result<(axum::http::StatusCode, Json<serde_json::Value>), AppError> {
    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
    require_role(&claims, &UserRole::Administrator)?;
    require_csrf_with_state(&headers, &claims, &state)?;

    let role = req.get("role").and_then(|v| v.as_str())
        .ok_or_else(|| AppError::Validation("role is required".to_string()))?;
    let resource = req.get("resource").and_then(|v| v.as_str())
        .ok_or_else(|| AppError::Validation("resource is required".to_string()))?;
    let action = req.get("action").and_then(|v| v.as_str())
        .ok_or_else(|| AppError::Validation("action is required".to_string()))?;

    let perm_id = uuid::Uuid::new_v4().to_string();
    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;

    db.execute(
        "INSERT INTO permissions (id, role, resource, action) VALUES (?1, ?2, ?3, ?4)",
        rusqlite::params![perm_id, role, resource, action],
    ).map_err(|e| {
        if e.to_string().contains("UNIQUE") {
            AppError::Conflict("Permission already exists".to_string())
        } else {
            AppError::Internal(e.to_string())
        }
    })?;

    let _ = crate::audit::chain::append_audit_log(
        &db, &claims.user_id, &claims.username, "CREATE", "permission", &perm_id,
        &serde_json::json!({"role": role, "resource": resource, "action": action}),
    );

    Ok((axum::http::StatusCode::CREATED, Json(serde_json::json!({
        "id": perm_id, "role": role, "resource": resource, "action": action
    }))))
}

pub async fn delete_permission(
    State(state): State<AppState>,
    headers: HeaderMap,
    Path(id): Path<String>,
) -> Result<Json<serde_json::Value>, AppError> {
    let claims = extract_claims_required(&headers, &state.hmac_secret)?;
    require_role(&claims, &UserRole::Administrator)?;
    require_csrf_with_state(&headers, &claims, &state)?;

    let db = state.db.lock().map_err(|e| AppError::Internal(e.to_string()))?;

    let deleted = db.execute("DELETE FROM permissions WHERE id = ?1", [&id])
        .map_err(|e| AppError::Internal(e.to_string()))?;

    if deleted == 0 {
        return Err(AppError::NotFound("Permission not found".to_string()));
    }

    let _ = crate::audit::chain::append_audit_log(
        &db, &claims.user_id, &claims.username, "DELETE", "permission", &id,
        &serde_json::json!({}),
    );

    Ok(Json(serde_json::json!({"message": "Permission deleted"})))
}

