pub async fn refresh_token() {
    if let Some(auth) = use_context::<AuthState>() {
        if let Ok(json) = api_get("/auth/me").await {
            if let Ok(val) = serde_wasm_bindgen::from_value::<serde_json::Value>(json) {
                if let Some(new_token) = val.get("refreshed_token").and_then(|t| t.as_str()) {
                    auth.token.set(Some(new_token.to_string()));
                }
            }
        }
    }
}

pub async fn api_get(path: &str) -> Result<JsValue, String> {
    let auth = use_context::<AuthState>().ok_or("No auth context")?;
    let opts = RequestInit::new();
    opts.set_method("GET");

    let headers = Headers::new().map_err(|e| format!("{:?}", e))?;
    if let Some(token) = auth.token.get_untracked() {
        headers.set("Authorization", &format!("Bearer {}", token)).map_err(|e| format!("{:?}", e))?;
    }
    opts.set_headers(&headers);

    let url = format!("/api{}", path);
    let request = Request::new_with_str_and_init(&url, &opts).map_err(|e| format!("{:?}", e))?;
    let window = web_sys::window().ok_or("No window")?;
    let resp_value = JsFuture::from(window.fetch_with_request(&request)).await.map_err(|e| format!("{:?}", e))?;
    let resp: Response = resp_value.dyn_into().map_err(|_| "Not a response")?;

    if resp.status() == 401 {
        auth.logout();
        return Err("Session expired".to_string());
    }

    let json = JsFuture::from(resp.json().map_err(|e| format!("{:?}", e))?).await.map_err(|e| format!("{:?}", e))?;

    // Refresh token on successful GET (idle timeout reset)
    if path != "/auth/me" {
        spawn_local(async { refresh_token().await; });
