use crate::security::route_guard::RouteGuard;
use crate::state::auth::AuthState;

#[component]
pub fn VehiclesPage() -> impl IntoView {
    let auth = use_context::<AuthState>().expect("AuthState");
    let vehicles = create_rw_signal(Vec::<crate::api::types::MaskedVehicle>::new());
    let loading = create_rw_signal(true);
    let upload_status = create_rw_signal(Option::<(bool, String)>::None);
    let selected_vehicle_id = create_rw_signal(Option::<String>::None);

    let load_vehicles = move || {
        spawn_local(async move {
            if let Ok(json) = crate::api::client::api_get("/vehicles").await {
                if let Ok(data) = serde_wasm_bindgen::from_value::<serde_json::Value>(json) {
                    if let Some(arr) = data.get("vehicles") {
                        if let Ok(list) = serde_json::from_value(arr.clone()) {
                            vehicles.set(list);
                        }
                    }
                }
            }
            loading.set(false);
        });
    };

    create_effect(move |_| { load_vehicles(); });

    let on_status_change = move |vehicle_id: String, new_status: String| {
        spawn_local(async move {
            let _ = crate::api::client::api_put(
                &format!("/vehicles/{}/status", vehicle_id),
                &serde_json::json!({"status": new_status}),
            ).await;
            load_vehicles();
        });
    };

    let on_upload = move |ev: leptos::ev::Event| {
        let input: web_sys::HtmlInputElement = event_target(&ev);
        if let Some(files) = input.files() {
            if let Some(file) = files.get(0) {
                let name = file.name();
                let size = file.size() as usize;
                if size > 10 * 1024 * 1024 {
                    upload_status.set(Some((false, "File exceeds 10 MB limit".into())));
                    return;
                }
                let ext = name.rsplit('.').next().unwrap_or("").to_lowercase();
                if ext != "jpg" && ext != "jpeg" && ext != "png" {
                    upload_status.set(Some((false, "Only JPEG and PNG files are accepted".into())));
                    return;
                }

                let vid = selected_vehicle_id.get_untracked().clone();
                spawn_local(async move {
                    let form_data = web_sys::FormData::new().unwrap();
                    let _ = form_data.append_with_blob("file", &file);
                    if let Some(ref v) = vid {
                        let _ = form_data.append_with_str("vehicle_id", v);
                    }
                    match crate::api::client::api_upload("/uploads", &form_data).await {
                        Ok((201, _)) => {
                            upload_status.set(Some((true, format!("Photo '{}' uploaded successfully", name))));
                        }
                        Ok((status, json)) => {
                            let msg = serde_wasm_bindgen::from_value::<serde_json::Value>(json)
                                .ok()
                                .and_then(|v| v.get("error").and_then(|e| e.get("message")).and_then(|m| m.as_str()).map(|s| s.to_string()))
                                .unwrap_or(format!("Upload failed (HTTP {})", status));
                            upload_status.set(Some((false, msg)));
                        }
                        Err(e) => upload_status.set(Some((false, e))),
                    }
                });
            }
        }
    };

    view! {
        <RouteGuard required_role="MerchantStaff">
            <h1>"Vehicle Management"</h1>
            <Show when=move || loading.get()>
                <p>"Loading vehicles..."</p>
            </Show>

            // Upload section
            <div class="card">
                <h2>"Upload Vehicle Photo"</h2>
                <div style="display: flex; gap: 1rem; align-items: end; flex-wrap: wrap;">
                    <div class="form-group" style="margin-bottom: 0;">
                        <label>"Vehicle (optional)"</label>
                        <select on:change=move |ev| {
                            let val = event_target_value(&ev);
                            selected_vehicle_id.set(if val.is_empty() { None } else { Some(val) });
                        }>
                            <option value="">"-- Select vehicle --"</option>
                            <For
                                each=move || vehicles.get()
                                key=|v| v.id.clone()
                                children=move |v| view! {
                                    <option value=v.id.clone()>{v.make.clone()} " " {v.model.clone()} " (" {v.license_plate.clone()} ")"</option>
                                }
                            />
                        </select>
                    </div>
                    <div class="form-group" style="margin-bottom: 0;">
                        <label>"Photo (JPEG/PNG, max 10 MB)"</label>
                        <input type="file" accept="image/jpeg,image/png" on:change=on_upload />
                    </div>
                </div>
                <Show when=move || upload_status.get().is_some()>
                    {move || {
                        let (ok, msg) = upload_status.get().unwrap();
                        view! {
                            <p style=format!("margin-top: 0.5rem; font-size: 0.875rem; color: {};", if ok { "#166534" } else { "#991b1b" })>
                                {msg}
                            </p>
                        }
                    }}
                </Show>
            </div>

            // Vehicle grid
            <div style="display: grid; grid-template-columns: repeat(auto-fill, minmax(320px, 1fr)); gap: 1rem;">
                <For
                    each=move || vehicles.get()
                    key=|v| v.id.clone()
                    children=move |v| {
                        let vid = v.id.clone();
                        let current_status = v.status.clone();
                        view! {
                            <div class="card">
                                <div style="display: flex; justify-content: space-between; align-items: start;">
                                    <h3>{v.make.clone()} " " {v.model.clone()} " " {v.trim_level.clone()}</h3>
                                    <crate::components::status_badge::StatusBadge status=v.status.clone() />
                                </div>
                                <table style="font-size: 0.875rem;">
                                    <tr><td style="font-weight: 500;">"VIN"</td><td class="masked">{v.vin.clone()}</td></tr>
                                    <tr><td style="font-weight: 500;">"Plate"</td><td class="masked">{v.license_plate.clone()}</td></tr>
                                    <tr><td style="font-weight: 500;">"Mileage"</td><td>{crate::utils::format::format_mileage(v.mileage_miles)}</td></tr>
                                    <tr><td style="font-weight: 500;">"Fuel/Battery"</td><td>{format!("{:.0}%", v.fuel_or_battery_pct)}</td></tr>
                                </table>
                                {v.insurance_expiry.as_ref().map(|d| view! {
                                    <p style="font-size: 0.75rem; color: #6b7280; margin-top: 0.5rem;">"Insurance: " {d.clone()}</p>
                                })}
                                {v.maintenance_due.as_ref().map(|d| view! {
                                    <p style="font-size: 0.75rem; color: #6b7280;">"Maintenance: " {d.clone()}</p>
                                })}
                                // Status transition buttons
                                <div style="margin-top: 0.5rem; display: flex; gap: 0.25rem; flex-wrap: wrap;">
                                    {if current_status == "available" {
                                        let vid2 = vid.clone();
                                        let vid3 = vid.clone();
                                        view! {
                                            <button class="btn" style="font-size: 0.7rem; padding: 0.2rem 0.5rem; background: #dbeafe;"
                                                on:click=move |_| on_status_change(vid2.clone(), "on-rent".into())>"Mark On-Rent"</button>
                                            <button class="btn" style="font-size: 0.7rem; padding: 0.2rem 0.5rem; background: #fee2e2;"
                                                on:click=move |_| on_status_change(vid3.clone(), "in-repair".into())>"Send to Repair"</button>
                                        }.into_view()
                                    } else if current_status == "on-rent" || current_status == "in-repair" {
                                        let vid2 = vid.clone();
                                        view! {
                                            <button class="btn" style="font-size: 0.7rem; padding: 0.2rem 0.5rem; background: #dcfce7;"
                                                on:click=move |_| on_status_change(vid2.clone(), "available".into())>"Return to Available"</button>
                                        }.into_view()
                                    } else {
                                        view! { <span style="font-size: 0.7rem; color: #9ca3af;">"No transitions available"</span> }.into_view()
                                    }}
                                </div>
                            </div>
                        }
                    }
                />
            </div>
        </RouteGuard>
    }
}
"}

