fn generate_qr_svg(data: &str) -> String {
    use qrcode::QrCode;
    match QrCode::new(data.as_bytes()) {
        Ok(code) => {
            let svg = code.render::<qrcode::render::svg::Color>()
                .min_dimensions(200, 200)
                .quiet_zone(true)
                .build();
            svg
        }
        Err(_) => {
            // Fallback: return the raw data if QR generation fails
            format!("<svg xmlns='http://www.w3.org/2000/svg' width='200' height='200'><text x='10' y='100' font-size='8'>{}</text></svg>", data)
        }
    }
}

